Class ScoreBoard Extends %RegisteredObject
{

    /// Sort scores from highest to lowest (numeric descending)
    ClassMethod SortScores(scores As %ListOfDataTypes) As %ListOfDataTypes
    {
        Set sorted = ##class(%ListOfDataTypes).%New()

        Set temp = ""
        For i=1:1:scores.Count() {
            Set val = scores.GetAt(i)
            Set temp(val) = ""
        }

        Set key = ""
        For {
            Set key = $ORDER(temp(key))
            Quit:key=""
            Do sorted.Insert(key)
        }

        Quit sorted
    }

}

