Class TestScoreBoard Extends %RegisteredObject
{

    ClassMethod TestSortScores()
    {
        Set scores = ##class(%ListOfDataTypes).%New()
        Do scores.Insert(100)
        Do scores.Insert(9)
        Do scores.Insert(50)
        Do scores.Insert(200)

        Set sorted = ##class(ScoreBoard).SortScores(scores)

        If (sorted.Count() '= 4) {
            Throw ##class(%Exception.General).%New("Expected 4 items, got "_sorted.Count())
        }

        If (sorted.GetAt(1) '= 200) {
            Throw ##class(%Exception.General).%New("First should be 200, got "_sorted.GetAt(1))
        }
        If (sorted.GetAt(2) '= 100) {
            Throw ##class(%Exception.General).%New("Second should be 100, got "_sorted.GetAt(2))
        }
        If (sorted.GetAt(3) '= 50) {
            Throw ##class(%Exception.General).%New("Third should be 50, got "_sorted.GetAt(3))
        }
        If (sorted.GetAt(4) '= 9) {
            Throw ##class(%Exception.General).%New("Fourth should be 9, got "_sorted.GetAt(4))
        }
    }

}
